// ─── helpers ─────────────────────────────────────────────────────────────────

function throws(fn, label) {
  let threw = false;
  try { fn(); } catch { threw = true; }
  assert(threw, `Expected exception: ${label}`);
}

function doesNotThrow(fn, label) {
  try { fn(); }
  catch (e) { assert(false, `Unexpected exception for "${label}": ${e.message}`); }
}

function freshSession() {
  return createEmptySession();
}

// rc.7 / 7e-3 · v3-pure test fixture helper. Bridges v2-shape test
// sessions (constructed via createEmptySession + addInstance + etc.)
// into the v3 engagementStore so v3-native views (MatrixView at 7e-3,
// GapsEditView at 7e-4, ...) see the test setup. Mutates the test's
// session in place: every v2 instance.id / env.id reference is
// rewritten to the v3 UUID generated during translation, so tests
// querying [data-instance-id='${inst.id}'] continue to work post-render.
//
// Idempotent — re-running on the same session is a no-op (all envs +
// instances already in v3). Test fixtures call this from inside
// mountMatrix() / mountGapsEdit() / etc. just before render.
//
// Authority: SPEC §S40 (v3-pure architecture); migration helper retires
// at 7e-8 alongside the v2 modules (Suite 13/14 tests get rewritten
// in the same commit to use v3 fixtures natively).
function _installSessionAsV3Engagement(s) {
  if (!s) return;
  // If already installed (re-mount case), skip.
  if (s._v3Installed) return;
  s._v3Installed = true;

  _resetEngagementStoreForTests();
  // rc.7 / 7e-8 redo Step G · _rearmBridgeMirrorForTests dropped (bridge
  // deleted; the cutover-window v3->v2 mirror no longer exists).
  setActiveEngagement(createEmptyEngagement());

  // Materialize envs. If the v2 session has session.environments, use
  // those (preserving hidden flag); else fall back to default-4 (the
  // v2 freshSession + getVisibleEnvironments fallback). PRESERVE the
  // hidden flag at materialization so SD2/SD6/SD8-style tests that
  // expect hidden envs in v3 see them. Earlier the filter dropped
  // hidden envs; now we forward them with hidden:true intact.
  var v2Envs = (Array.isArray(s.environments) && s.environments.length > 0)
    ? s.environments
    : ["coreDc", "drDc", "publicCloud", "edge"].map(function(id) { return { id, hidden: false }; });

  var envUuidMap = {};
  v2Envs.forEach(function(v2env) {
    if (!v2env || !v2env.id || envUuidMap[v2env.id]) return;
    var input = { envCatalogId: v2env.id, hidden: !!v2env.hidden };
    if (typeof v2env.alias    === "string" && v2env.alias.length    > 0) input.alias    = v2env.alias;
    if (typeof v2env.location === "string" && v2env.location.length > 0) input.location = v2env.location;
    if (typeof v2env.sizeKw   === "number") input.sizeKw   = v2env.sizeKw;
    if (typeof v2env.sqm      === "number") input.sqm      = v2env.sqm;
    if (typeof v2env.tier     === "string" && v2env.tier.length     > 0) input.tier     = v2env.tier;
    if (typeof v2env.notes    === "string") input.notes    = v2env.notes;
    var r = commitEnvAdd(input);
    if (r && r.engagement) {
      var eng = r.engagement;
      for (var i = 0; i < eng.environments.allIds.length; i++) {
        var e = eng.environments.byId[eng.environments.allIds[i]];
        if (e.envCatalogId === v2env.id && !envUuidMap[v2env.id]) {
          envUuidMap[v2env.id] = e.id;
          break;
        }
      }
    }
  });

  // Materialize instances in two passes — current first, then desired
  // (so originId references resolve via instUuidMap).
  var instUuidMap = {};  // v2 inst.id -> v3 uuid

  function _addOne(v2inst) {
    var input = {
      state:         v2inst.state || "current",
      layerId:       v2inst.layerId,
      environmentId: envUuidMap[v2inst.environmentId] || v2inst.environmentId,
      label:         v2inst.label || "",
      vendor:        v2inst.vendor || "",
      vendorGroup:   v2inst.vendorGroup || "custom",
      // v3 schema requires criticality enum non-null; default to "Medium"
      // when v2 omits (matches createEmptyInstance default).
      criticality:   v2inst.criticality || "Medium",
      notes:         v2inst.notes || "",
      // v3 schema requires disposition non-empty; default to "keep"
      // when v2 omits.
      disposition:   v2inst.disposition || "keep",
      originId:      v2inst.originId ? (instUuidMap[v2inst.originId] || null) : null,
      priority:      v2inst.priority || null,
      mappedAssetIds: Array.isArray(v2inst.mappedAssetIds)
        ? v2inst.mappedAssetIds.map(function(id) { return instUuidMap[id] || id; })
        : []
    };
    var r = commitInstanceAdd(input);
    if (r && r.engagement) {
      var eng = r.engagement;
      var found = null;
      for (var i = eng.instances.allIds.length - 1; i >= 0; i--) {
        var inst = eng.instances.byId[eng.instances.allIds[i]];
        if (inst && inst.label === input.label && inst.layerId === input.layerId
            && inst.environmentId === input.environmentId && inst.state === input.state) {
          found = inst;
          break;
        }
      }
      if (found) {
        instUuidMap[v2inst.id] = found.id;
        // Mutate v2 instance in place so test code holding `inst`
        // references the v3 UUID for [data-instance-id] lookups.
        v2inst.id = found.id;
        v2inst.environmentId = input.environmentId;
      }
    }
  }

  (s.instances || []).filter(function(i) { return i.state !== "desired"; }).forEach(_addOne);
  (s.instances || []).filter(function(i) { return i.state === "desired"; }).forEach(_addOne);

  // rc.7 / 7e-8b' · materialize drivers from session.customer.drivers
  // so v3-pure ContextView (which reads engagement.drivers) sees the
  // test fixture's setup. v2 driver shape: { id (= businessDriverId),
  // priority, outcomes }.
  var v2Drivers = (s.customer && Array.isArray(s.customer.drivers)) ? s.customer.drivers : [];
  v2Drivers.forEach(function(v2d) {
    if (!v2d || !v2d.id) return;
    commitDriverAdd({
      businessDriverId: v2d.id,
      priority:         v2d.priority || "Medium",
      outcomes:         typeof v2d.outcomes === "string" ? v2d.outcomes : ""
    });
  });

  // rc.7 / 7e-8b' · migrate customer scalar fields (name, vertical,
  // region, notes) from v2 session.customer to v3 engagement.customer
  // so v3-pure ContextView reads correct data. createEmptyCustomer
  // populates default placeholders ("New customer", etc.); replace
  // with the test fixture's values where present.
  if (s.customer) {
    // v3 CustomerSchema: name + vertical are min(1); only patch when
    // the test fixture supplies non-empty values. Empty strings would
    // fail .strict() validation; we leave the createEmptyCustomer
    // defaults ("New customer", "Financial Services") in place when
    // the test session is empty.
    var customerPatch = {};
    if (typeof s.customer.name     === "string" && s.customer.name.length     > 0) customerPatch.name     = s.customer.name;
    if (typeof s.customer.vertical === "string" && s.customer.vertical.length > 0) customerPatch.vertical = s.customer.vertical;
    if (typeof s.customer.region   === "string") customerPatch.region   = s.customer.region;
    if (typeof s.customer.notes    === "string") customerPatch.notes    = s.customer.notes;
    if (Object.keys(customerPatch).length > 0) {
      commitContextEdit({ customer: customerPatch });
    }
  }

  // Materialize gaps. v2 gap shape: { id, description, layerId,
  // affectedLayers (catalog refs), affectedEnvironments (catalog refs),
  // relatedCurrentInstanceIds (v2 ids), relatedDesiredInstanceIds (v2 ids),
  // driverId (businessDriverId), gapType, urgency, phase, status, ...}.
  // v3: same shape but UUID-keyed. Translate refs through envUuidMap +
  // instUuidMap + driverIdMap.
  var driverBusIdToV3Uuid = {};
  var engForDrivers = getActiveEngagement();
  if (engForDrivers && engForDrivers.drivers && Array.isArray(engForDrivers.drivers.allIds)) {
    engForDrivers.drivers.allIds.forEach(function(uuid) {
      var d = engForDrivers.drivers.byId[uuid];
      if (d && d.businessDriverId) driverBusIdToV3Uuid[d.businessDriverId] = d.id;
    });
  }
  var gapUuidMap = {};   // v2 id -> v3 uuid

  (s.gaps || []).forEach(function(v2gap) {
    if (!v2gap || !v2gap.layerId) return;
    var v3GapInput = {
      description:               (typeof v2gap.description === "string" && v2gap.description.length > 0)
                                   ? v2gap.description : "Gap",
      gapType:                   v2gap.gapType || "replace",
      urgency:                   v2gap.urgency || "Medium",
      urgencyOverride:           !!v2gap.urgencyOverride,
      phase:                     v2gap.phase || "now",
      status:                    v2gap.status || "open",
      reviewed:                  !!v2gap.reviewed,
      notes:                     v2gap.notes || "",
      driverId:                  v2gap.driverId ? (driverBusIdToV3Uuid[v2gap.driverId] || null) : null,
      layerId:                   v2gap.layerId,
      affectedLayers:            (Array.isArray(v2gap.affectedLayers) && v2gap.affectedLayers.length > 0)
                                   ? v2gap.affectedLayers
                                   : [v2gap.layerId],
      // Translate env refs. Drop any catalog ref that didn't map (test
      // session may reference an env that wasn't materialized).
      affectedEnvironments:      Array.isArray(v2gap.affectedEnvironments)
                                   ? v2gap.affectedEnvironments
                                       .map(function(cid) { return envUuidMap[cid] || cid; })
                                       .filter(function(uuid) {
                                         // v3 schema requires UUIDs; drop bare catalog refs that didn't map.
                                         return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(uuid);
                                       })
                                   : [],
      relatedCurrentInstanceIds: Array.isArray(v2gap.relatedCurrentInstanceIds)
                                   ? v2gap.relatedCurrentInstanceIds.map(function(vid) { return instUuidMap[vid] || vid; })
                                       .filter(function(uuid) {
                                         return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(uuid);
                                       })
                                   : [],
      relatedDesiredInstanceIds: Array.isArray(v2gap.relatedDesiredInstanceIds)
                                   ? v2gap.relatedDesiredInstanceIds.map(function(vid) { return instUuidMap[vid] || vid; })
                                       .filter(function(uuid) {
                                         return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(uuid);
                                       })
                                   : [],
      services:                  Array.isArray(v2gap.services) ? v2gap.services.slice() : []
    };
    // v3 GapSchema requires affectedEnvironments.min(1). If translation
    // dropped all UUIDs, default to the first materialized env so the
    // commit doesn't fail validation. Tests that DON'T pre-populate
    // envs hit this — accept the fallback as test-fixture pragmatism.
    if (v3GapInput.affectedEnvironments.length === 0) {
      var firstEnvUuid = Object.values(envUuidMap)[0] || null;
      if (firstEnvUuid) v3GapInput.affectedEnvironments = [firstEnvUuid];
    }
    var r = commitGapAdd(v3GapInput);
    if (r && r.engagement) {
      var eng = r.engagement;
      // Find the just-added gap by description match (should be unique
      // enough at fixture time).
      var found = null;
      for (var i = eng.gaps.allIds.length - 1; i >= 0; i--) {
        var g = eng.gaps.byId[eng.gaps.allIds[i]];
        if (g && g.description === v3GapInput.description && g.layerId === v3GapInput.layerId) {
          found = g;
          break;
        }
      }
      if (found) {
        gapUuidMap[v2gap.id] = found.id;
        v2gap.id = found.id;
        // Also rewrite v2 gap's env / instance refs to UUIDs in place
        // so test assertions on s.gaps[i] see consistent v3 shape.
        v2gap.affectedEnvironments      = found.affectedEnvironments.slice();
        v2gap.relatedCurrentInstanceIds = found.relatedCurrentInstanceIds.slice();
        v2gap.relatedDesiredInstanceIds = found.relatedDesiredInstanceIds.slice();
        if (found.driverId) v2gap.driverId = found.driverId;
      }
    }
  });

  // Propagate v2 isDemo to v3 engagement.meta (the v3-native carrier).
  // v3-pure views (MatrixView, etc.) read engagement.meta.isDemo for
  // demo-banner rendering. The install helper writes through directly
  // because there's no adapter helper for engagement.meta updates yet
  // (v3 model treats meta as derived; demo flag is an exception we
  // surface here for test parity).
  if (s.isDemo === true) {
    var engNow = getActiveEngagement();
    if (engNow && engNow.meta) {
      setActiveEngagement({ ...engNow, meta: { ...engNow.meta, isDemo: true } });
    }
  }

  // Install a transient v3 -> v2 instance + env mirror that reflects
  // v3 changes back into the test's `s` object. This is what makes
  // T6.11 / T6.12 / similar tests work: they call commitInstanceAdd
  // (via the +Add palette UI) which writes v3, then assert on
  // s.instances. Without the mirror, s.instances stays at the
  // pre-render snapshot and assertions fail.
  //
  // The mirror unsubscribes when _resetEngagementStoreForTests runs
  // (the next install call clears _subs), so it's per-test scoped.
  // rc.7 / 7e-8 redo Step G · was: "production code uses state/
  // sessionBridge.js's mirror for v2 readers." That bridge is gone.
  // This test-only mirror keeps `s` in sync with v3 commits during
  // the v2-fixture-pattern rewrite arc (Step I retires the pattern).
  subscribeActiveEngagement(function _testMirrorIntoS(eng) {
    if (!eng) return;
    if (!s) return;
    // Rebuild s.instances as v2-shape entries from v3 collection.
    var nextInstances = [];
    if (eng.instances && Array.isArray(eng.instances.allIds)) {
      for (var i = 0; i < eng.instances.allIds.length; i++) {
        var v3i = eng.instances.byId[eng.instances.allIds[i]];
        if (!v3i) continue;
        var v2i = {
          id:            v3i.id,
          state:         v3i.state,
          layerId:       v3i.layerId,
          environmentId: v3i.environmentId,
          label:         v3i.label,
          vendor:        v3i.vendor,
          vendorGroup:   v3i.vendorGroup,
          criticality:   v3i.criticality,
          notes:         v3i.notes,
          disposition:   v3i.disposition
        };
        if (v3i.priority   !== null && v3i.priority   !== undefined) v2i.priority   = v3i.priority;
        if (v3i.originId   !== null && v3i.originId   !== undefined) v2i.originId   = v3i.originId;
        if (Array.isArray(v3i.mappedAssetIds) && v3i.mappedAssetIds.length > 0) v2i.mappedAssetIds = v3i.mappedAssetIds.slice();
        nextInstances.push(v2i);
      }
    }
    s.instances = nextInstances;
    // Rebuild s.environments as v2-shape entries from v3.
    var nextEnvs = [];
    if (eng.environments && Array.isArray(eng.environments.allIds)) {
      for (var j = 0; j < eng.environments.allIds.length; j++) {
        var v3e = eng.environments.byId[eng.environments.allIds[j]];
        if (!v3e) continue;
        var v2e = { id: v3e.envCatalogId, hidden: !!v3e.hidden };
        if (typeof v3e.alias    === "string" && v3e.alias.length    > 0) v2e.alias    = v3e.alias;
        if (typeof v3e.location === "string" && v3e.location.length > 0) v2e.location = v3e.location;
        if (typeof v3e.sizeKw   === "number") v2e.sizeKw = v3e.sizeKw;
        if (typeof v3e.sqm      === "number") v2e.sqm    = v3e.sqm;
        if (typeof v3e.tier     === "string" && v3e.tier.length     > 0) v2e.tier     = v3e.tier;
        if (typeof v3e.notes    === "string" && v3e.notes.length    > 0) v2e.notes    = v3e.notes;
        nextEnvs.push(v2e);
      }
    }
    s.environments = nextEnvs;
    // Mirror gaps too (Suite 14's GapsEditView fixture in 7e-4 will
    // need them; cheap to do here so 7e-4 doesn't have to extend).
    var nextGaps = [];
    if (eng.gaps && Array.isArray(eng.gaps.allIds)) {
      for (var k = 0; k < eng.gaps.allIds.length; k++) {
        var v3g = eng.gaps.byId[eng.gaps.allIds[k]];
        if (v3g) nextGaps.push({ ...v3g });
      }
    }
    s.gaps = nextGaps;
    // Mirror customer + drivers (v2 shape: { id (= businessDriverId),
    // priority, outcomes }) + isDemo. T1.17 etc. read
    // s.customer.drivers[0].outcomes after a v3 commit; the mirror
    // back-fills the test's s reference each emit so the assertion
    // sees the post-commit value without manual refresh.
    if (eng.customer && s.customer) {
      s.customer.name     = eng.customer.name     || s.customer.name     || "";
      s.customer.vertical = eng.customer.vertical || s.customer.vertical || "";
      s.customer.region   = eng.customer.region   || s.customer.region   || "";
      s.customer.notes    = eng.customer.notes    || s.customer.notes    || "";
    }
    // Rebuild s.customer.drivers from v3 engagement.drivers so tests
    // that assert on s.customer.drivers[i].priority / .outcomes after
    // a v3 commit see the post-commit value (the v3 commit fires the
    // engagementStore emit which calls this subscriber).
    if (s.customer) {
      var nextDrivers = [];
      if (eng.drivers && Array.isArray(eng.drivers.allIds)) {
        for (var di = 0; di < eng.drivers.allIds.length; di++) {
          var v3d = eng.drivers.byId[eng.drivers.allIds[di]];
          if (!v3d) continue;
          nextDrivers.push({
            id:       v3d.businessDriverId,
            priority: v3d.priority || "Medium",
            outcomes: typeof v3d.outcomes === "string" ? v3d.outcomes : ""
          });
        }
      }
      s.customer.drivers = nextDrivers;
    }
    if (eng.meta && typeof eng.meta.isDemo === "boolean") s.isDemo = eng.meta.isDemo;
  });

  // Trigger one immediate mirror cycle so post-install s state matches v3.
  setActiveEngagement(getActiveEngagement());
}

function validInstance(overrides = {}) {
  return {
    id: "inst-test-" + Math.random().toString(36).slice(2, 7),
    state: "current",
    layerId: LayerIds[0],
    environmentId: EnvironmentIds[0],
    label: "Test Server",
    vendor: "Dell",
    vendorGroup: "dell",
    ...overrides
  };
}

function validGap(overrides = {}) {
  return {
    id: "gap-test-" + Math.random().toString(36).slice(2, 7),
    description: "Test gap",
    layerId: LayerIds[0],
    affectedLayers: [],
    affectedEnvironments: [],
    urgency: "Medium",
    phase: "now",
    mappedDellSolutions: "",
    notes: "",
    relatedCurrentInstanceIds: [],
    relatedDesiredInstanceIds: [],
    status: "open",
    ...overrides
  };
}


