      assertEqual(toolMsg.tool_call_id, "call_xyz", "tool_call_id mirrors the assistant tool_calls.id");
      assertEqual(toolMsg.content, "{\"counts\":{\"open\":1}}",
        "tool message content carries the tool_result string");
