    var allSet = mod.getAllMutableDataPoints && mod.getAllMutableDataPoints();
    assert(Array.isArray(standardSet), "V-FLOW-SKILL-V32-CURATION-2 (RED-until-R2): getStandardMutableDataPoints() MUST return an Array");
